// Overlap / Layout component — overlap-style-01 (card offset) and split-layout (50/50)

export interface OverlapCard {
  title: string;
  subtitle?: string;
}

interface OverlapProps {
  title?: string;
  subtitle?: string;
  bgColor?: string;
  cards?: OverlapCard[];
  cols?: number;
}

export function OverlapStyle01({
  title = "We build great things.",
  subtitle = "Full-stack design and development for companies that care about quality.",
  bgColor = "var(--dark)",
  cards = [{ title: "Strategy" }, { title: "Design" }, { title: "Development" }],
  cols = 3,
}: OverlapProps) {
  return (
    <div className="overlap-style-01" style={{ paddingBottom: "5rem" }}>
      <div
        className="ov-bg"
        style={{ background: bgColor, padding: "4rem 3rem 5rem", textAlign: "center" }}
      >
        <h2 style={{ color: "#fff", fontSize: "clamp(1.75rem,3vw,3rem)", marginBottom: "1rem" }}>{title}</h2>
        <p style={{ color: "rgba(255,255,255,.6)", maxWidth: 440, margin: "0 auto", fontSize: ".9375rem" }}>{subtitle}</p>
      </div>
      <div
        className="ov-cards"
        style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}
      >
        {cards.map((c, i) => (
          <div key={i} className="ov-card">
            <h6>{c.title}</h6>
            {c.subtitle && <p>{c.subtitle}</p>}
          </div>
        ))}
      </div>
    </div>
  );
}

interface SplitProps {
  leftTitle?: string;
  leftText?: string;
  rightTitle?: string;
  rightText?: string;
}

export function SplitLayout({
  leftTitle = "Designed for impact.",
  leftText = "Every component is crafted with intention, tested for performance, and built for scale.",
  rightTitle = "Built for teams.",
  rightText = "Consistent tokens, clear documentation, and a design system that scales with your organization.",
}: SplitProps) {
  return (
    <div className="split-layout">
      <div className="sl-left">
        <h3>{leftTitle}</h3>
        <p>{leftText}</p>
      </div>
      <div className="sl-right">
        <h3>{rightTitle}</h3>
        <p>{rightText}</p>
      </div>
    </div>
  );
}
