// Mirrors React-template Lists.jsx — list-style-01, 02, 03

import type { ReactNode } from "react";

export interface ListItem {
  icon?: ReactNode;
  title?: string;
  content: string;
  link?: string;
}

interface Props {
  theme?: "list-style-01" | "list-style-02" | "list-style-03" | "list-style-04" | "list-style-05" | "list-style-06" | "list-style-07" | "list-style-08";
  data: ListItem[];
}

export default function Lists({ theme = "list-style-02", data }: Props) {
  if (theme === "list-style-01") {
    return (
      <ul className="list-01 space-y-1">
        {data.map((item, i) => <li key={i}>{item.content}</li>)}
      </ul>
    );
  }
  if (theme === "list-style-03") {
    return (
      <ul className="list-03">
        {data.map((item, i) => <li key={i}>{item.content}</li>)}
      </ul>
    );
  }
  if (theme === "list-style-04") {
    return (
      <ul className="list-style-04">
        {data.map((item, i) => <li key={i}>{item.content}</li>)}
      </ul>
    );
  }
  if (theme === "list-style-05") {
    return (
      <ul className="list-style-05">
        {data.map((item, i) => <li key={i}>{item.content}</li>)}
      </ul>
    );
  }
  if (theme === "list-style-06") {
    return (
      <ul className="list-style-06">
        {data.map((item, i) => <li key={i}>{item.content}</li>)}
      </ul>
    );
  }
  if (theme === "list-style-07") {
    return (
      <ul className="list-style-07">
        {data.map((item, i) => (
          <li key={i}>
            <span className="li-icon">{item.icon || "★"}</span>
            <div>
              {item.title && <div className="li-title">{item.title}</div>}
              <div className="li-desc">{item.content}</div>
            </div>
          </li>
        ))}
      </ul>
    );
  }
  if (theme === "list-style-08") {
    return (
      <ul className="list-style-08">
        {data.map((item, i) => (
          <li key={i}>
            <a href={item.link || "#"}>{item.content}</a>
            {item.title && <span className="li-count">{item.title}</span>}
          </li>
        ))}
      </ul>
    );
  }
  // style-02 (default)
  return (
    <ul className="list-02">
      {data.map((item, i) => (
        <li key={i}>
          <span className="l-icon">✓</span>
          <span>{item.content}</span>
        </li>
      ))}
    </ul>
  );
}
